<template>
    <div>
        <h1>second3</h1>
        <!-- node-key="label"
      :default-expanded-keys='["三级 2-1-1"]'
      :default-checked-keys='["三级 2-1-1"]' -->
        <el-tree
            :data="data"
            :props="defaultProps"
            @node-click="handleNodeClick"/>
        <div>
            <label>图片1:</label>
            <div class='bar' :style="{'--percent': num}"/>
        </div>
    </div>
</template>
<script>
    export default {
        data() {
            return {
                num: 0,
                data: [{
                    label: '一级 1',
                    children: [{
                        label: '二级 1-1',
                        children: [{
                            label: '三级 1-1-1'
                        }]
                    }]
                }, {
                    label: '一级 2',
                    children: [{
                        label: '二级 2-1',
                        children: [{
                            label: '三级 2-1-1'
                        }]
                    }, {
                        label: '二级 2-2',
                        children: [{
                            label: '三级 2-2-1'
                        }]
                    }]
                }, {
                    label: '一级 3',
                    children: [{
                        label: '二级 3-1',
                        children: [{
                            label: '三级 3-1-1'
                        }]
                    }, {
                        label: '二级 3-2',
                        children: [{
                            label: '三级 3-2-1'
                        }]
                    }]
                }],
                defaultProps: {
                    children: 'children',
                    label: 'label'
                }
            };
        },
        created() {
            setInterval(() => {
                this.num++;
                if(this.num >100) {
                    this.num = 0;
                }
            }, 100)
        },
        methods: {
            handleNodeClick(data) {
                console.log(data);
            }
        }
    }
</script>
<style scoped lang='scss'>
.bar {
    display: inline-block;
    height: 20px; width: 300px;
    background-color: #f5f5f5;
}
.bar::before {
    counter-reset: progress var(--percent);
    content: counter(progress) '%\2002';
    display: block;
    width: calc(300px * var(--percent) / 100);
    font-size: 12px;
    color: #fff;
    background-color: #2486ff;
    text-align: right;
    white-space: nowrap;
    overflow: hidden;
}
</style>

